#include<bits/stdc++.h>
using namespace std;

int main()
{
    long long n,ans=0;
    scanf("%lld",&n);
    for(long long i=0;(i==0?1:(1ll<<(i-1))+1)<=n;i++)
    {
        long long l=(i==0?1:(1ll<<(i-1))+1),r=min(n,1ll<<i);
        ans+=(r-l+1)%998244353*(i+1)%998244353;
        ans%=998244353;
    }
    printf("%lld",ans%998244353);
    return 0;
}
